// == nümunəsi
const number = 5;
const string = '5';
console.log(number == string); // true (tip çevirməsi ilə)

// === nümunəsi
console.log(number === string); // false (tip fərqlidir)

// Digər nümunə
console.log(0 == false); // true (tip çevirməsi ilə)
console.log(0 === false); // false (tip fərqlidir)

// != nümunəsi
const value1 = 10;
const value2 = '10';
console.log(value1 != value2); // false (tip çevirməsi ilə bərabərdir)

// !== nümunəsi
console.log(value1 !== value2); // true (tip fərqlidir)

// Digər nümunə
console.log(null != undefined); // false (tip çevirməsi ilə bərabərdir)
console.log(null !== undefined); // true (tip fərqlidir)

// Relyasiya operatorları nümunəsi
const a = 15;
const b = 10;
console.log(a > b); // true
console.log(a < b); // false
console.log(a >= b); // true
console.log(a <= b); // false

// Sətir müqayisəsi
const str1 = 'alma';
const str2 = 'armud';
console.log(str1 < str2); // true (Unicode sırasına görə)

// Şərtli ifadə nümunəsi
const age = 18;
if (age >= 18) {
  console.log('Yetkinsən!');
} else {
  console.log('Yetkin deyilsən.');
}
// Çıxış: Yetkinsən!

// Bərabərlik yoxlaması
const userInput = 'hello';
if (userInput === 'hello') {
  console.log('Doğru giriş!');
} else {
  console.log('Yanlış giriş.');
}
// Çıxış: Doğru giriş!

// Səhvə yol açan nümunə
// Səhv: == ilə tip çevirməsi
const input = '0';
if (input == false) {
  console.log('Giriş yalandır.');
} else {
  console.log('Giriş doğrudur.');
}
// Çıxış: Giriş yalandır. (səhv, çünki '0' false-a çevrilir)

// Düzgün yol: === ilə
const input2 = '0';
if (input2 === false) {
  console.log('Giriş yalandır.');
} else {
  console.log('Giriş doğrudur.');
}
// Çıxış: Giriş doğrudur.

