// == example
const number = 5;
const string = '5';
console.log(number == string); // true (with type coercion)

// === example
console.log(number === string); // false (types are different)

// Another example
console.log(0 == false); // true (with type coercion)
console.log(0 === false); // false (types are different)

// != example
const value1 = 10;
const value2 = '10';
console.log(value1 != value2); // false (equal with type coercion)

// !== example
console.log(value1 !== value2); // true (types are different)

// Another example
console.log(null != undefined); // false (equal with type coercion)
console.log(null !== undefined); // true (types are different)

// Relational operators example
const a = 15;
const b = 10;
console.log(a > b); // true
console.log(a < b); // false
console.log(a >= b); // true
console.log(a <= b); // false

// String comparison
const str1 = 'apple';
const str2 = 'banana';
console.log(str1 < str2); // true (based on Unicode order)

// Conditional statement example
const age = 18;
if (age >= 18) {
  console.log('You are an adult!');
} else {
  console.log('You are not an adult.');
}
// Output: You are an adult!

// Equality check
const userInput = 'hello';
if (userInput === 'hello') {
  console.log('Correct input!');
} else {
  console.log('Incorrect input.');
}
// Output: Correct input!

// Error-prone example
// Error: == with type coercion
const input = '0';
if (input == false) {
  console.log('Input is false.');
} else {
  console.log('Input is true.');
}
// Output: Input is false. (wrong, because '0' coerces to false)

// Correct approach: ===
const input2 = '0';
if (input2 === false) {
  console.log('Input is false.');
} else {
  console.log('Input is true.');
}
// Output: Input is true.

