// Пример ==
const number = 5;
const string = '5';
console.log(number == string); // true (с приведением типов)

// Пример ===
console.log(number === string); // false (типы разные)

// Другой пример
console.log(0 == false); // true (с приведением типов)
console.log(0 === false); // false (типы разные)

// Пример !=
const value1 = 10;
const value2 = '10';
console.log(value1 != value2); // false (равны с приведением типов)

// Пример !==
console.log(value1 !== value2); // true (типы разные)

// Другой пример
console.log(null != undefined); // false (равны с приведением типов)
console.log(null !== undefined); // true (типы разные)

// Пример реляционных операторов
const a = 15;
const b = 10;
console.log(a > b); // true
console.log(a < b); // false
console.log(a >= b); // true
console.log(a <= b); // false

// Сравнение строк
const str1 = 'яблоко';
const str2 = 'банан';
console.log(str1 < str2); // true (по порядку Unicode)

// Пример условного выражения
const age = 18;
if (age >= 18) {
  console.log('Вы взрослый!');
} else {
  console.log('Вы не взрослый.');
}
// Вывод: Вы взрослый!

// Проверка равенства
const userInput = 'привет';
if (userInput === 'привет') {
  console.log('Правильный ввод!');
} else {
  console.log('Неправильный ввод.');
}
// Вывод: Правильный ввод!

// Пример с ошибкой
// Ошибка: == с приведением типов
const input = '0';
if (input == false) {
  console.log('Ввод ложный.');
} else {
  console.log('Ввод истинный.');
}
// Вывод: Ввод ложный. (ошибка, так как '0' приводится к false)

// Правильный подход: ===
const input2 = '0';
if (input2 === false) {
  console.log('Ввод ложный.');
} else {
  console.log('Ввод истинный.');
}
// Вывод: Ввод истинный.

